{
  "name": "EmailGenius AI",
  "description": "A high-performance email marketing suite that generates complete campaigns with high-converting copy and stunning AI visuals powered by Gemini.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ImageSize = '1K' | '2K' | '4K';

export interface CampaignContent {
  subject: string;
  headline: string;
  body: string;
  ctaText: string;
  visualPrompt: string;
}

export interface Campaign {
  id: string;
  timestamp: number;
  content: CampaignContent;
  imageUrl?: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CampaignContent, ImageSize } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateEmailCampaign = async (prompt: string): Promise<CampaignContent> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a complete email marketing campaign based on this request: "${prompt}". 
    The response must be in JSON format with fields: subject, headline, body, ctaText, and visualPrompt (a detailed prompt for an image generator to create a banner visual for this email).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          headline: { type: Type.STRING },
          body: { type: Type.STRING },
          ctaText: { type: Type.STRING },
          visualPrompt: { type: Type.STRING }
        },
        required: ["subject", "headline", "body", "ctaText", "visualPrompt"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Failed to parse campaign JSON");
  }
};

export const generateCampaignImage = async (prompt: string, size: ImageSize): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: prompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
        imageSize: size
      }
    }
  });

  const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imagePart?.inlineData) {
    return `data:image/png;base64,${imagePart.inlineData.data}`;
  }
  throw new Error("No image was generated");
};

export const chatWithGemini = async (history: { role: string; text: string }[], message: string): Promise<string> => {
  const ai = getAIClient();
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: 'You are EmailGenius Assistant, a world-class marketing expert. Help users optimize their email campaigns, strategy, and creative direction.'
    }
  });

  // Sending the message. For simplicity with the provided SDK example, we'll just send the current message.
  // In a full implementation, you'd rebuild the history.
  const result = await chat.sendMessage({ message });
  return result.text || "I'm sorry, I couldn't process that.";
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'danger';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";
  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 active:scale-[0.98]",
    secondary: "bg-slate-800 text-white hover:bg-slate-900 active:scale-[0.98]",
    outline: "border border-slate-300 text-slate-700 hover:bg-slate-50 active:scale-[0.98]",
    danger: "bg-red-500 text-white hover:bg-red-600 active:scale-[0.98]",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`} 
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processing...
        </>
      ) : children}
    </button>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithGemini } from '../services/geminiService';

export const ChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hi! I am your EmailGenius assistant. How can I help you today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    try {
      const response = await chatWithGemini(messages, userMessage);
      setMessages(prev => [...prev, { role: 'model', text: response }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: 'Sorry, I encountered an error. Please try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-white rounded-2xl shadow-2xl w-80 md:w-96 flex flex-col border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-8 h-8 bg-white/20 rounded-full flex items-center justify-center">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
              </div>
              <span className="font-semibold">EmailGenius AI</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-1 rounded">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 h-96 overflow-y-auto p-4 space-y-4 bg-slate-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] rounded-2xl px-4 py-2 text-sm ${
                  m.role === 'user' 
                    ? 'bg-indigo-600 text-white rounded-br-none' 
                    : 'bg-white text-slate-700 shadow-sm border border-slate-200 rounded-bl-none'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white text-slate-700 shadow-sm border border-slate-200 rounded-2xl rounded-bl-none px-4 py-2 text-sm flex gap-1">
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                  <span className="w-1.5 h-1.5 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                </div>
              </div>
            )}
          </div>

          <form onSubmit={handleSend} className="p-4 border-t border-slate-200 bg-white">
            <div className="flex gap-2">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask me anything..."
                className="flex-1 bg-slate-100 border-none rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
              />
              <button 
                type="submit"
                disabled={isLoading}
                className="bg-indigo-600 text-white p-2 rounded-lg hover:bg-indigo-700 disabled:opacity-50"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
              </button>
            </div>
          </form>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-indigo-600 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center hover:bg-indigo-700 hover:scale-110 transition-all duration-200 group"
        >
          <svg className="w-7 h-7 transition-transform group-hover:rotate-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z"></path></svg>
        </button>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ImageSize, Campaign, CampaignContent } from './types';
import { generateEmailCampaign, generateCampaignImage } from './services/geminiService';
import { Button } from './components/Button';
import { ChatWidget } from './components/ChatWidget';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [imageSize, setImageSize] = useState<ImageSize>('1K');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [currentCampaign, setCurrentCampaign] = useState<Campaign | null>(null);
  const [history, setHistory] = useState<Campaign[]>([]);
  const [isApiKeyChecking, setIsApiKeyChecking] = useState(true);
  const [hasApiKey, setHasApiKey] = useState(false);

  useEffect(() => {
    checkApiKey();
  }, []);

  const checkApiKey = async () => {
    try {
      // @ts-ignore - Assuming window.aistudio exists in the environment
      const selected = await window.aistudio.hasSelectedApiKey();
      setHasApiKey(selected);
    } catch (e) {
      // If we're not in the AI Studio frame or it's not supported, assume true for testing or external use
      setHasApiKey(true);
    } finally {
      setIsApiKeyChecking(false);
    }
  };

  const handleOpenKeySelector = async () => {
    try {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    } catch (e) {
      console.error("Failed to open key selector");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt.trim() || isLoading) return;

    setIsLoading(true);
    setError(null);

    try {
      // Step 1: Generate Copy
      const content = await generateEmailCampaign(prompt);

      // Step 2: Generate Visuals (using the high-quality model)
      const imageUrl = await generateCampaignImage(content.visualPrompt, imageSize);

      const newCampaign: Campaign = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        content,
        imageUrl
      };

      setCurrentCampaign(newCampaign);
      setHistory(prev => [newCampaign, ...prev]);
    } catch (err: any) {
      console.error(err);
      if (err.message?.includes("Requested entity was not found")) {
        setHasApiKey(false);
        setError("API Key issue. Please re-select your key.");
      } else {
        setError(err.message || "Something went wrong while generating your campaign.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  if (isApiKeyChecking) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-50">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-12 h-12 bg-indigo-600 rounded-full mb-4"></div>
          <p className="text-slate-600 font-medium">Initializing EmailGenius AI...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 text-slate-900">
      {/* Header */}
      <header className="sticky top-0 z-30 w-full bg-white/80 backdrop-blur-md border-b border-slate-200">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold">E</div>
            <h1 className="text-xl font-bold bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">EmailGenius AI</h1>
          </div>
          <div className="flex items-center gap-4">
            {!hasApiKey && (
              <Button onClick={handleOpenKeySelector} variant="outline" className="text-sm">
                Connect API Key
              </Button>
            )}
            <div className="hidden md:flex items-center gap-2 text-sm text-slate-500 font-medium">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              AI Core Ready
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Input Column */}
        <div className="lg:col-span-4 space-y-6">
          <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
              <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
              Campaign Architect
            </h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">What's the goal?</label>
                <textarea 
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="e.g. A summer sale campaign for our new sustainable sneakers, highlighting a 20% discount and eco-friendly materials."
                  className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-sm transition-all"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Visual Quality (Gemini 3 Pro Image)</label>
                <div className="grid grid-cols-3 gap-2">
                  {(['1K', '2K', '4K'] as ImageSize[]).map((size) => (
                    <button
                      key={size}
                      type="button"
                      onClick={() => setImageSize(size)}
                      className={`py-2 rounded-lg text-xs font-semibold border transition-all ${
                        imageSize === size 
                          ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                          : 'bg-white border-slate-200 text-slate-600 hover:border-indigo-300'
                      }`}
                    >
                      {size} Resolution
                    </button>
                  ))}
                </div>
              </div>

              <Button 
                type="submit" 
                className="w-full py-3" 
                isLoading={isLoading}
                disabled={!prompt.trim() || !hasApiKey}
              >
                Generate Campaign
              </Button>

              {!hasApiKey && (
                <p className="text-[10px] text-center text-slate-400 mt-2">
                  <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline">Billing Setup</a> required for Gemini 3 Pro features.
                </p>
              )}

              {error && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl text-red-600 text-xs">
                  {error}
                  {!hasApiKey && (
                    <button onClick={handleOpenKeySelector} className="block mt-1 font-bold underline">Fix Key Connection</button>
                  )}
                </div>
              )}
            </form>
          </section>

          {/* History Snippet */}
          <section className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-4">Recent Generations</h2>
            <div className="space-y-3">
              {history.length === 0 ? (
                <p className="text-xs text-slate-400 italic">No previous campaigns yet.</p>
              ) : (
                history.map(item => (
                  <button 
                    key={item.id}
                    onClick={() => setCurrentCampaign(item)}
                    className="w-full text-left p-2 rounded-lg hover:bg-slate-50 border border-transparent hover:border-slate-200 transition-all flex items-center gap-3"
                  >
                    <img src={item.imageUrl} className="w-10 h-10 rounded object-cover" alt="" />
                    <div className="overflow-hidden">
                      <p className="text-xs font-medium truncate">{item.content.subject}</p>
                      <p className="text-[10px] text-slate-400">{new Date(item.timestamp).toLocaleDateString()}</p>
                    </div>
                  </button>
                ))
              )}
            </div>
          </section>
        </div>

        {/* Output Column */}
        <div className="lg:col-span-8">
          {currentCampaign ? (
            <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden animate-in fade-in zoom-in-95 duration-500">
              {/* Email Client Shell */}
              <div className="bg-slate-100 p-4 border-b border-slate-200 flex items-center gap-2">
                <div className="flex gap-1.5">
                  <div className="w-3 h-3 rounded-full bg-red-400"></div>
                  <div className="w-3 h-3 rounded-full bg-amber-400"></div>
                  <div className="w-3 h-3 rounded-full bg-green-400"></div>
                </div>
                <div className="flex-1 bg-white mx-4 rounded-md h-7 border border-slate-200 flex items-center px-3 text-[10px] text-slate-400 truncate">
                  {currentCampaign.content.subject}
                </div>
              </div>

              <div className="p-8 md:p-12 space-y-8 max-w-2xl mx-auto">
                <div className="space-y-1">
                  <p className="text-sm text-slate-400">Subject:</p>
                  <h3 className="text-lg font-bold text-slate-900">{currentCampaign.content.subject}</h3>
                </div>

                <div className="rounded-2xl overflow-hidden shadow-lg aspect-video bg-slate-100 flex items-center justify-center relative group">
                  <img 
                    src={currentCampaign.imageUrl} 
                    alt="Campaign Visual" 
                    className="w-full h-full object-cover"
                  />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <span className="bg-white/20 backdrop-blur px-3 py-1.5 rounded-full text-xs text-white font-medium border border-white/30">
                      Generated at {imageSize}
                    </span>
                  </div>
                </div>

                <div className="space-y-6">
                  <h2 className="text-3xl font-extrabold text-indigo-900 leading-tight">
                    {currentCampaign.content.headline}
                  </h2>
                  <div className="prose prose-slate prose-indigo max-w-none">
                    <p className="text-lg text-slate-600 leading-relaxed whitespace-pre-wrap">
                      {currentCampaign.content.body}
                    </p>
                  </div>
                  <div className="pt-4">
                    <button className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 px-10 rounded-xl shadow-lg shadow-indigo-200 transition-all hover:-translate-y-1 active:scale-95">
                      {currentCampaign.content.ctaText}
                    </button>
                  </div>
                </div>

                <div className="pt-12 border-t border-slate-100">
                  <div className="flex justify-between items-center text-slate-400 text-xs">
                    <p>© 2024 Your Brand Inc. | 123 Marketing Blvd.</p>
                    <div className="flex gap-4">
                      <button className="hover:text-indigo-600 underline">Unsubscribe</button>
                      <button className="hover:text-indigo-600 underline">View in Browser</button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-center p-8 bg-white/50 border-2 border-dashed border-slate-200 rounded-3xl">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6">
                <svg className="w-10 h-10 text-indigo-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg>
              </div>
              <h3 className="text-xl font-bold text-slate-700 mb-2">Ready to launch your campaign?</h3>
              <p className="text-slate-500 max-w-md mx-auto">
                Fill out the architect form on the left to generate high-converting copy and professional banners in seconds.
              </p>
              {isLoading && (
                <div className="mt-12 flex flex-col items-center gap-4">
                  <div className="flex gap-2">
                    <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce [animation-delay:0s]"></div>
                    <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                    <div className="w-3 h-3 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                  </div>
                  <p className="text-sm font-medium text-indigo-600 italic">Gemini is sketching your visuals...</p>
                </div>
              )}
            </div>
          )}
        </div>
      </main>

      {/* Floating Chatbot */}
      <ChatWidget />

      <footer className="py-6 border-t border-slate-200 bg-white">
        <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row justify-between items-center gap-4 text-sm text-slate-500">
          <p>© 2024 EmailGenius AI. Powered by Google Gemini.</p>
          <div className="flex gap-6">
            <a href="#" className="hover:text-indigo-600 transition-colors">Privacy</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Terms</a>
            <a href="#" className="hover:text-indigo-600 transition-colors">Documentation</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export type ImageSize = '1K' | '2K' | '4K';
export type Language = 'en' | 'pt';

export interface CampaignContent {
  subject: string;
  headline: string;
  body: string;
  ctaText: string;
  visualPrompt: string;
}

export interface Campaign {
  id: string;
  timestamp: number;
  content: CampaignContent;
  imageUrl?: string;
  language: Language;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CampaignContent, ImageSize, Language } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const generateEmailCampaign = async (prompt: string, lang: Language): Promise<CampaignContent> => {
  const ai = getAIClient();
  const langContext = lang === 'pt' ? "em Português do Brasil" : "in English";

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a complete email marketing campaign based on this request: "${prompt}". 
    The campaign must be written ${langContext}.
    The response must be in JSON format with fields: subject, headline, body, ctaText, and visualPrompt (a detailed prompt in English for an image generator to create a banner visual for this email).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          subject: { type: Type.STRING },
          headline: { type: Type.STRING },
          body: { type: Type.STRING },
          ctaText: { type: Type.STRING },
          visualPrompt: { type: Type.STRING }
        },
        required: ["subject", "headline", "body", "ctaText", "visualPrompt"]
      }
    }
  });

  try {
    return JSON.parse(response.text || '{}');
  } catch (e) {
    throw new Error("Failed to parse campaign JSON");
  }
};

export const generateCampaignImage = async (prompt: string, size: ImageSize): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [{ text: prompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9",
        imageSize: size
      }
    }
  });

  const imagePart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
  if (imagePart?.inlineData) {
    return `data:image/png;base64,${imagePart.inlineData.data}`;
  }
  throw new Error("No image was generated");
};

export const chatWithGemini = async (history: { role: string; text: string }[], message: string, lang: Language): Promise<string> => {
  const ai = getAIClient();
  const langContext = lang === 'pt' ? "Responda sempre em Português do Brasil." : "Always respond in English.";

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: `You are EmailGenius Assistant, a world-class marketing expert. Help users optimize their email campaigns, strategy, and creative direction. ${langContext}`
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text || (lang === 'pt' ? "Desculpe, não consegui processar isso." : "I'm sorry, I couldn't process that.");
};

import React, { useState, useRef, useEffect } from 'react';
