                <h2 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-4">{t.templatesLabel}</h2>
                <div className="grid grid-cols-2 gap-2">
                  {templates.map(tmp => (
                    <button
                      key={tmp.id}
