                </button>
              </div>
              <div className="p-8 md:p-12 space-y-8 max-w-2xl mx-auto">
                <div className="space-y-1">
                  <div className="flex items-center gap-3 mb-2">
                    <p className="text-[10px] uppercase font-bold text-indigo-400 tracking-widest">{currentCampaign.templateId?.toUpperCase() || 'CUSTOM'}</p>
                    <span className="text-[10px] text-slate-300">•</span>
                    <p className="text-[10px] text-slate-400 font-medium uppercase">{formatDate(currentCampaign.timestamp)}</p>
                  </div>
                  <h3 className="text-2xl font-bold text-slate-900 leading-tight">{currentCampaign.content.subject}</h3>
                </div>
                <div className="rounded-2xl overflow-hidden shadow-2xl aspect-video bg-slate-100 group relative">
                  <img src={currentCampaign.imageUrl} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" alt="" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent pointer-events-none"></div>
                </div>
                <div className="space-y-6">
                  <h2 className="text-3xl font-extrabold text-indigo-950 leading-tight">{currentCampaign.content.headline}</h2>
                  <p className="text-lg text-slate-600 leading-relaxed whitespace-pre-wrap">{currentCampaign.content.body}</p>
                  <button className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 px-10 rounded-xl shadow-xl shadow-indigo-100 transition-all hover:-translate-y-1 active:scale-95">
                    {currentCampaign.content.ctaText}
                  </button>
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full min-h-[500px] flex flex-col items-center justify-center text-center p-8 bg-white/50 border-2 border-dashed border-slate-200 rounded-3xl">
              <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6"><svg className="w-10 h-10 text-indigo-200" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10"></path></svg></div>
              <h3 className="text-xl font-bold text-slate-700 mb-2">{t.emptyStateTitle}</h3>
              <p className="text-slate-400 text-sm max-w-sm mx-auto">{t.emptyStateDesc}</p>
              {isLoading && <div className="mt-8 flex flex-col items-center gap-3"><div className="flex gap-1.5"><div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce"></div><div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div><div className="w-2 h-2 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.4s]"></div></div><p className="text-xs font-medium text-indigo-600">{t.loadingVisuals}</p></div>}
            </div>
          )}
        </div>
      </main>

      {showSendModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center"><h3 className="text-lg font-bold text-slate-800">{t.sendModalTitle}</h3><button onClick={() => setShowSendModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg></button></div>
            <div className="p-6 space-y-4">
              <textarea value={recipients} onChange={(e) => setRecipients(e.target.value)} placeholder={t.recipientsPlaceholder} disabled={isSending} className="w-full h-32 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none text-sm resize-none transition-all" />
              {isSending && sendProgress && (
                <div className="space-y-2"><div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>{t.sendingMsg.replace('{current}', sendProgress.current.toString()).replace('{total}', sendProgress.total.toString())}</span><span>{Math.round((sendProgress.current / sendProgress.total) * 100)}%</span></div><div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden"><div className="bg-emerald-500 h-full transition-all duration-300" style={{ width: `${(sendProgress.current/sendProgress.total)*100}%` }} /></div></div>
