                <div className="space-y-2"><div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>{t.sendingMsg.replace('{current}', sendProgress.current.toString()).replace('{total}', sendProgress.total.toString())}</span><span>{Math.round((sendProgress.current / sendProgress.total) * 100)}%</span></div><div className="w-full bg-slate-100 h-1.5 rounded-full overflow-hidden"><div className="bg-emerald-500 h-full transition-all duration-300" style={{ width: `${(sendProgress.current/sendProgress.total)*100}%` }} /></div></div>
              )}
